10	export function DashboardPage(
11	  runs: EvalRun[],
12	  agentsPerRun: Map<string, string[]>,
13	  stats: GlobalStats,
14	  pagination?: PaginationInfo
15	): string {
16	  // AC-3: Empty state when 0 runs total
17	  if (stats.total === 0) {
18	    return `
19	      <div class="page-title">
20	        <h1>DreamTeam Eval Dashboard</h1>
21	        <p>No eval runs found. Run an eval to see results here.</p>
22	      </div>
23	      <div class="empty-state">No eval data found in database.</div>
24	    `;
25	  }
26	
27	  // AC-5: Stat cards always reflect ALL runs globally via pre-computed stats
28	  const { total, baselines, latestRun: latest } = stats;
29	  const latestRate = latest ? pct(latest.pass_rate) : "—";
30	
31	  const statsHtml = `
32	    <div class="stat-cards">
33	      <div class="stat-card">
34	        <div class="stat-label">Total Runs</div>
35	        <div class="stat-value accent">${total}</div>
36	      </div>
37	      <div class="stat-card">
38	        <div class="stat-label">Baselines</div>
39	        <div class="stat-value accent">${baselines}</div>
40	      </div>
41	      <div class="stat-card">
42	        <div class="stat-label">Latest Pass Rate</div>
43	        <div class="stat-value pass">${latestRate}</div>
44	      </div>
45	      <div class="stat-card">
46	        <div class="stat-label">Latest Pass</div>
47	        <div class="stat-value pass">${latest?.pass_count ?? 0}</div>
48	      </div>
49	      <div class="stat-card">
50	        <div class="stat-label">Latest Partial</div>
51	        <div class="stat-value partial">${latest?.partial_count ?? 0}</div>
52	      </div>
53	      <div class="stat-card">
54	        <div class="stat-label">Latest Fail</div>
55	        <div class="stat-value fail">${latest?.fail_count ?? 0}</div>
56	      </div>
57	    </div>
58	  `;
59	
60	  const rowsHtml = runs.map(run => {
61	    const rate = run.pass_rate ?? 0;
62	    let badgesHtml = "";
63	    if (run.is_complete_baseline) {
64	      badgesHtml = `<span class="run-baseline">BASELINE</span>`;
65	    } else {
66	      const agents = (agentsPerRun.get(run.run_id) ?? []).sort();
67	      badgesHtml = agents.map(a => agentChip(a)).join("");
68	    }
69	
70	    return `
71	      <a href="/evals/${encodeURIComponent(run.run_id)}" class="run-row">
72	        <div class="run-meta">
73	          <span class="run-date">${esc(formatDate(run.timestamp))}</span>
74	        </div>
75	        <div class="run-counts">
76	          <span class="p">${run.pass_count ?? 0}P</span>
77	          <span class="pa">${run.partial_count ?? 0}p</span>
78	          <span class="f">${run.fail_count ?? 0}F</span>
79	        </div>
80	        <div>${passBar(run.pass_count, run.partial_count, run.fail_count)}</div>
81	        <div class="run-passrate">${pct(rate)}</div>
