101	      .btn-new-run { display:inline-flex; align-items:center; background:var(--accent); color:#fff; border-radius:6px; padding:8px 16px; font-size:13px; font-weight:600; text-decoration:none; white-space:nowrap; transition:opacity 0.15s; }
