115	function pageLink(pageNum: number, label: string, cls: string = ""): string {
116	  const href = pageNum === 1 ? "/" : `/?page=${pageNum}`;
117	  const hxGet = pageNum === 1 ? "/" : `/?page=${pageNum}`;
118	  return `<a class="page-link${cls ? " " + cls : ""}" href="${href}" hx-get="${hxGet}" hx-target=".container" hx-push-url="true">${label}</a>`;
119	}
120	
121	function renderPagination(p: PaginationInfo): string {
122	  const { page, totalPages } = p;
123	  const hasPrev = page > 1;
124	  const hasNext = page < totalPages;
125	
126	  // Prev arrow
127	  const prev = hasPrev
128	    ? pageLink(page - 1, "&lsaquo;")
129	    : `<span class="page-link disabled">&lsaquo;</span>`;
130	
131	  // Next arrow
132	  const next = hasNext
133	    ? pageLink(page + 1, "&rsaquo;")
134	    : `<span class="page-link disabled">&rsaquo;</span>`;
135	
